{"type":"doc","content":[{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Коротко: делай запрос в "},{"type":"text","marks":[{"type":"code"}],"text":"useEffect"},{"type":"text","text":" с "},{"type":"text","marks":[{"type":"bold"}],"text":"пустым массивом зависимостей "},{"type":"text","marks":[{"type":"code"}],"text":"[]"},{"type":"text","text":" (только при первом монтировании), не забывай про "},{"type":"text","marks":[{"type":"bold"}],"text":"отмену"},{"type":"text","text":" и "},{"type":"text","marks":[{"type":"bold"}],"text":"обработку ошибок"},{"type":"text","text":". Ниже — надёжный шаблон."}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { useEffect, useState, useRef } from "react";

export function UserOnce() {
  const [data, setData]   = useState(null);
  const [error, setError] = useState(null);
  const [loading, setLoading] = useState(true);

  // Страховка от двойного вызова эффекта в Dev-режиме (StrictMode) в React 18
  const didRunRef = useRef(false);

  useEffect(() => {
    if (didRunRef.current) return;      // не даём запуститься второй раз в Dev
    didRunRef.current = true;

    const controller = new AbortController();

    (async () => {
      try {
        setLoading(true);
        const res = await fetch("/api/user", { signal: controller.signal });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const json = await res.json();
        setData(json);                   // обновляем состояние только если не отменили
      } catch (e) {
        if (e.name !== "AbortError") setError(e);
      } finally {
        setLoading(false);
      }
    })();

    // cleanup: отменяем запрос при размонтировании
    return () => controller.abort();
  }, []); // ← только первый рендер (монтирование)

  if (loading) return <p>Loading…</p>;
  if (error)   return <p>Error: {String(error.message || error)}</p>;
  return <pre>{JSON.stringify(data, null, 2)}</pre>;
}
