{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"🚫 Проблема"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Если компонент размонтируется (например, пользователь ушёл со страницы),"},{"type":"hardBreak"},{"type":"text","text":"а асинхронный запрос ("},{"type":"text","marks":[{"type":"code"}],"text":"fetch"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"axios"},{"type":"text","text":", "},{"type":"text","marks":[{"type":"code"}],"text":"setTimeout"},{"type":"text","text":") ещё выполняется —"},{"type":"hardBreak"},{"type":"text","text":"он "},{"type":"text","marks":[{"type":"bold"}],"text":"всё равно завершится"},{"type":"text","text":", и вы попытаетесь вызвать "},{"type":"text","marks":[{"type":"code"}],"text":"setState"},{"type":"text","text":" на уже удалённом компоненте."}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"Результат:"},{"type":"hardBreak"},{"type":"text","text":"⚠️ предупреждение в консоли"},{"type":"hardBreak"},{"type":"text","text":"🧠 лишняя нагрузка на сеть"},{"type":"hardBreak"},{"type":"text","text":"💾 утечка памяти"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":2},"content":[{"type":"text","text":"✅ Решение — отмена запроса в cleanup-функции "},{"type":"text","marks":[{"type":"code"}],"text":"useEffect"}]},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"Вариант 1. "},{"type":"text","marks":[{"type":"bold"}],"text":"С "},{"type":"text","marks":[{"type":"code"}],"text":"AbortController"},{"type":"text","marks":[{"type":"bold"}],"text":" (встроено в fetch)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { useEffect, useState } from "react";

function UserProfile({ id }) {
  const [user, setUser] = useState(null);
  const [error, setError] = useState(null);

  useEffect(() => {
    // Создаём контроллер отмены
    const controller = new AbortController();
    const signal = controller.signal;

    // Выполняем асинхронный запрос
    async function loadUser() {
      try {
        const res = await fetch(`/api/users/${id}`, { signal });
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        const data = await res.json();
        setUser(data);
      } catch (err) {
        // Игнорируем ошибку, если запрос был отменён
        if (err.name !== "AbortError") setError(err);
      }
    }

    loadUser();

    // Возвращаем cleanup-функцию — отменяем запрос при размонтировании
    return () => controller.abort();
  }, [id]);

  if (error) return <p>Ошибка: {error.message}</p>;
  if (!user) return <p>Загрузка...</p>;
  return <p>Имя: {user.name}</p>;
