{"type":"doc","content":[{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"1) Базовый спиннер по флагу "},{"type":"text","marks":[{"type":"code"}],"text":"loading"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import { useEffect, useState } from "react";

export function Users() {
  const [data, setData] = useState<any[] | null>(null);
  const [loading, setLoading] = useState(true);
  const [err, setErr] = useState<Error | null>(null);

  useEffect(() => {
    (async () => {
      try {
        const res = await fetch("/api/users");
        if (!res.ok) throw new Error(`HTTP ${res.status}`);
        setData(await res.json());
      } catch (e: any) {
        setErr(e);
      } finally {
        setLoading(false);
      }
    })();
  }, []);

  if (loading) return <Loader ariaLabel="Загрузка пользователей…" />;
  if (err) return <p role="alert">Ошибка: {err.message}</p>;
  return <ul>{data!.map(u => <li key={u.id}>{u.name}</li>)}</ul>;
}

function Loader({ ariaLabel = "Загрузка…" }: { ariaLabel?: string }) {
  return (
    <div className="loader" role="status" aria-live="polite" aria-label={ariaLabel} />
  );
}"}]},{"type":"paragraph","attrs":{"textAlign":null}}]}

