function useLikePost() {
  const queryClient = useQueryClient();

  return useMutation({
    mutationFn: (postId) => fetch(`/api/posts/${postId}/like`, { method: 'POST' }),

    // 1️⃣ Оптимистично обновляем кэш
    onMutate: async (postId) => {
      await queryClient.cancelQueries(['post', postId]);
      const prevPost = queryClient.getQueryData(['post', postId]);

      queryClient.setQueryData(['post', postId], (old) => ({
        ...old,
        likes: old.likes + 1,
        isLiked: true,
      }));

      // 2️⃣ Возвращаем данные для rollback
      return { prevPost };
    },

    // 3️⃣ Если ошибка — откатываем
    onError: (err, postId, context) => {
      queryClient.setQueryData(['post', postId], context.prevPost);
    },

    // 4️⃣ После успеха — обновляем или инвалидируем
    onSettled: (postId) => {
      queryClient.invalidateQueries(['post', postId]);
    },
  });
}
"}]},{"type":"paragraph","attrs":{"textAlign":null},"content":[{"type":"text","text":"📘 "},{"type":"text","marks":[{"type":"code"}],"text":"onMutate"},{"type":"text","text":" → локальное обновление"},{"type":"hardBreak"},{"type":"text","text":"📘 "},{"type":"text","marks":[{"type":"code"}],"text":"onError"},{"type":"text","text":" → откат"},{"type":"hardBreak"},{"type":"text","text":"📘 "},{"type":"text","marks":[{"type":"code"}],"text":"onSettled"},{"type":"text","text":" → финальное обновление/валидация"}]},{"type":"horizontalRule"},{"type":"heading","attrs":{"textAlign":null,"level":3},"content":[{"type":"text","text":"🧩 2. "},{"type":"text","marks":[{"type":"bold"}],"text":"SWR (Vercel)"}]},{"type":"codeBlock","attrs":{"language":"javascript"},"content":[{"type":"text","text":"import useSWR, { mutate } from 'swr';

